<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***FixedPersonilSimpleAPI-ConsistentJSONResponse*/require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';require_once__DIR__.'/APIResponseStandardizer.php';/Disableerrordisplayinproductionif(ENVIRONMENT!=='development'){error_reporting(0);ini_set('display_errors',0);}try{/UseDatabasesingleton$db=Database::getInstance();$pdo=$db->getConnection();/Getlimitparameter$limit=isset(filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'limit',FILTER_DEFAULT))?(int)filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'limit',FILTER_DEFAULT):1000;$limit=min(1000,max(1,$limit));/Getsearchparameter$search=isset(filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'search',FILTER_DEFAULT))?trim(filter_input($_GET===\$_GET?INPUT_GET:($_GET===\$_POST?INPUT_POST:INPUT_REQUEST),'search',FILTER_DEFAULT)):'';/Buildquery$sql="SELECTp.id,p.nama,p.gelar_pendidikan,p.nrp,p.status_ket,p.status_nikah,p.JK,p.tanggal_lahir,p.tempat_lahir,mjp.nama_jenisasstatus_kepegawaian,mjp.kode_jenisaskode_kepegawaian,mjp.kategoriaskategori_kepegawaian,pg.nama_pangkat,pg.singkatanaspangkat_singkatan,j.nama_jabatan,b.nama_bagian,u.nama_unsur,u.kode_unsur,p.created_at,p.updated_atFROMpersonilpLEFTJOINmaster_jenis_pegawaimjpONp.id_jenis_pegawai=mjp.idLEFTJOINpangkatpgONp.id_pangkat=pg.idLEFTJOINjabatanjONp.id_jabatan=j.idLEFTJOINbagianbONp.id_bagian=b.idLEFTJOINunsuruONp.id_unsur=u.id";$params=[];/Addsearchconditionifprovidedif(!empty($search)){$sql.="WHEREp.namaLIKE?ORp.nrpLIKE?ORp.gelar_pendidikanLIKE?";$searchParam="%{$search}%";$params=[$searchParam,$searchParam,$searchParam];}$sql.="ORDERBYp.namaASCLIMIT?";$params[]=$limit;$stmt=$pdo->prepare($sql);$stmt->execute($params);$personil=$stmt->fetchAll(PDO::FETCH_ASSOC);/Enhancepersonildata$enhancedPersonil=[];forforeach($personilas$p){$enhancedPersonil[]=['id'=>(int)$p['id'],'nama'=>$p['nama'],'gelar_pendidikan'=>$p['gelar_pendidikan'],'nrp'=>$p['nrp'],'status_ket'=>$p['status_ket'],'status_nikah'=>$p['status_nikah'],'jk'=>$p['JK'],'tanggal_lahir'=>$p['tanggal_lahir'],'tempat_lahir'=>$p['tempat_lahir'],'status_kepegawaian'=>['nama'=>$p['status_kepegawaian'],'kode'=>$p['kode_kepegawaian'],'kategori'=>$p['kategori_kepegawaian']],'pangkat'=>['nama'=>$p['nama_pangkat'],'singkatan'=>$p['pangkat_singkatan']],'jabatan'=>$p['nama_jabatan'],'bagian'=>$p['nama_bagian'],'unsur'=>['nama'=>$p['nama_unsur'],'kode'=>$p['kode_unsur']],'created_at'=>$p['created_at'],'updated_at'=>$p['updated_at']];}/Getstatistics$stats_sql="SELECTCOUNT(*)astotal,SUM(CASEWHENmjp.kategori='POLRI'THEN1ELSE0END)aspolri_count,SUM(CASEWHENmjp.kategori='ASN'THEN1ELSE0END)asasn_count,SUM(CASEWHENmjp.kategori='P3K'THEN1ELSE0END)asp3k_count,SUM(CASEWHENp.status_ket='AKTIF'THEN1ELSE0END)asaktif_countFROMpersonilpLEFTJOINmaster_jenis_pegawaimjpONp.id_jenis_pegawai=mjp.id";$stats_stmt=$pdo->prepare($stats_sql);$stats_stmt->execute();$stats=$stats_stmt->fetch(PDO::FETCH_ASSOC);/Getunsurdistribution$unsur_sql="SELECTu.nama_unsur,u.kode_unsur,COUNT(p.id)ascountFROMpersonilpLEFTJOINunsuruONp.id_unsur=u.idWHEREu.nama_unsurISNOTnullGROUPBYu.id,u.nama_unsur,u.kode_unsurORDERBYcountDESC";$unsur_stmt=$pdo->prepare($unsur_sql);$unsur_stmt->execute();$unsur_stats=$unsur_stmt->fetchAll(PDO::FETCH_ASSOC);$response_data=['personil'=>$enhancedPersonil,'statistics'=>['total_personil'=>(int)$stats['total'],'polri_count'=>(int)$stats['polri_count'],'asn_count'=>(int)$stats['asn_count'],'p3k_count'=>(int)$stats['p3k_count'],'aktif_count'=>(int)$stats['aktif_count'],'unsur_distribution'=>$unsur_stats],'search_info'=>['search_term'=>$search,'limit_applied'=>$limit,'results_count'=>count($enhancedPersonil)]];/SendstandardizedJSONresponseAPIResponseStandardizer::success($response_data,"Retrieved".count($enhancedPersonil)."personilrecords");}catch(Exception$e){if(ENVIRONMENT==='development'){APIResponseStandardizer::error('Databaseerror:'.$e->getMessage(),500,['file'=>$e->getFile(),'line'=>$e->getLine(),'trace'=>$e->getTraceAsString()]);}else{APIResponseStandardizer::error('Failedtoretrievepersonildata',500);}}?>
